<?php/** * Created by PhpStorm. * User: Cyril * Date: 29/01/2017 * Time: 11:05 */class ExternalLink{    private $link;    private $alphabet;    private $size;    public function __construct($size=8)    {        $this->size = $size;        $this->alphabet =  Array('a', 'b', 'c', 'd', 'e', 'f', 'g', 'h', 'j', 'k', 'm', 'n', 'p', 'q', 'r', 's', 't', 'u', 'v', 'w', 'x', 'y', 'z', 'A', 'B', 'C', 'D', 'E', 'F', 'G', 'H', 'J', 'K', 'L', 'M', 'N', 'P', 'Q', 'R', 'S', 'T', 'U', 'V', 'W', 'X', 'Y', 'Z', 2, 3, 4, 5, 6, 7, 8, 9);        $longueur_tableau = count($this->alphabet);        for($i=0; $i<$size; $i++)            $this->link .= $this->alphabet[rand(0, $longueur_tableau-1)];    }    public function nombreCombinaison()    {        return 'Nombre de possibilités avec un alphabet de longueur '.count($this->alphabet).' et un mot de '.$this->size.' digits à générer : <strong>'.pow(count($this->alphabet), $this->size).'</strong>';    }    public function __toString()    {        return $this->link;    }}